    ///<summary><p>Retrieves the details of a PaymentIntent that has previously been created. </p>
    ///<p>You can retrieve a PaymentIntent client-side using a publishable key when the <code>client_secret</code> is in the query string. </p>
    ///<p>If you retrieve a PaymentIntent with a publishable key, it only returns a subset of properties. Refer to the <a href="#payment_intent_object">payment intent</a> object reference for more details.</p></summary>
    let Retrieve settings (options: RetrieveOptions) =
        let qs = [("client_secret", options.ClientSecret |> box); ("expand", options.Expand |> box)] |> Map.ofList
        $"/v1/payment_intents/{options.Intent}"
        |> RestApi.getAsync<PaymentIntent> settings qs

