    type UpdateOptions = {
        [<Config.Path>]Intent: string
        ///<summary>Amount intended to be collected by this PaymentIntent. A positive integer representing how much to charge in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal) (e.g., 100 cents to charge $1.00 or 100 to charge ¥100, a zero-decimal currency). The minimum amount is $0.50 US or [equivalent in charge currency](https://docs.stripe.com/currencies#minimum-and-maximum-charge-amounts). The amount value supports up to eight digits (e.g., a value of 99999999 for a USD charge of $999,999.99).</summary>
        [<Config.Form>]Amount: int option
        ///<summary>Provides industry-specific information about the amount.</summary>
        [<Config.Form>]AmountDetails: Choice<Update'AmountDetailsAmountDetails,string> option
        ///<summary>The amount of the application fee (if any) that will be requested to be applied to the payment and transferred to the application owner's Stripe account. The amount of the application fee collected will be capped at the total amount captured. For more information, see the PaymentIntents [use case for connected accounts](https://docs.stripe.com/payments/connected-accounts).</summary>
        [<Config.Form>]ApplicationFeeAmount: Choice<int,string> option
        ///<summary>Controls when the funds will be captured from the customer's account.</summary>
        [<Config.Form>]CaptureMethod: Update'CaptureMethod option
        ///<summary>Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).</summary>
        [<Config.Form>]Currency: IsoTypes.IsoCurrencyCode option
        ///<summary>ID of the Customer this PaymentIntent belongs to, if one exists.
        ///Payment methods attached to other Customers cannot be used with this PaymentIntent.
        ///If [setup_future_usage](https://api.stripe.com#payment_intent_object-setup_future_usage) is set and this PaymentIntent's payment method is not `card_present`, then the payment method attaches to the Customer after the PaymentIntent has been confirmed and any required actions from the user are complete. If the payment method is `card_present` and isn't a digital wallet, then a [generated_card](https://docs.stripe.com/api/charges/object#charge_object-payment_method_details-card_present-generated_card) payment method representing the card is created and attached to the Customer instead.</summary>
        [<Config.Form>]Customer: string option
        ///<summary>ID of the Account representing the customer that this PaymentIntent belongs to, if one exists.
        ///Payment methods attached to other Accounts cannot be used with this PaymentIntent.
        ///If [setup_future_usage](https://api.stripe.com#payment_intent_object-setup_future_usage) is set and this PaymentIntent's payment method is not `card_present`, then the payment method attaches to the Account after the PaymentIntent has been confirmed and any required actions from the user are complete. If the payment method is `card_present` and isn't a digital wallet, then a [generated_card](https://docs.stripe.com/api/charges/object#charge_object-payment_method_details-card_present-generated_card) payment method representing the card is created and attached to the Account instead.</summary>
        [<Config.Form>]CustomerAccount: string option
