    ///<summary><p>Capture the funds of an existing uncaptured PaymentIntent when its status is <code>requires_capture</code>.</p>
    ///<p>Uncaptured PaymentIntents are cancelled a set number of days (7 by default) after their creation.</p>
    ///<p>Learn more about <a href="/docs/payments/capture-later">separate authorization and capture</a>.</p></summary>
    let Capture settings (options: CaptureOptions) =
        $"/v1/payment_intents/{options.Intent}/capture"
        |> RestApi.postAsync<_, PaymentIntent> settings (Map.empty) options

