    ///<a href="/docs/api/charges/object#charge_object-payment_method_details-card_present-incremental_authorization_supported">incremental_authorization_supported</a>
    ///must be <code>true</code>.</p>
    ///<p>Incremental authorizations attempt to increase the authorized amount on
    ///your customer’s card to the new, higher <code>amount</code> provided. Similar to the
    ///initial authorization, incremental authorizations can be declined. A
    ///single PaymentIntent can call this endpoint multiple times to further
    ///increase the authorized amount.</p>
    ///<p>If the incremental authorization succeeds, the PaymentIntent object
    ///returns with the updated
    ///<a href="/docs/api/payment_intents/object#payment_intent_object-amount">amount</a>.
    ///If the incremental authorization fails, a
    ///<a href="/docs/error-codes#card-declined">card_declined</a> error returns, and no other
    ///fields on the PaymentIntent or Charge update. The PaymentIntent
    ///object remains capturable for the previously authorized amount.</p>
    ///<p>Each PaymentIntent can have a maximum of 10 incremental authorization attempts, including declines.
    ///After it’s captured, a PaymentIntent can no longer be incremented.</p>
    ///<p>Learn more about <a href="/docs/terminal/features/incremental-authorizations">incremental authorizations</a>.</p></summary>
    let IncrementAuthorization settings (options: IncrementAuthorizationOptions) =
        $"/v1/payment_intents/{options.Intent}/increment_authorization"
        |> RestApi.postAsync<_, PaymentIntent> settings (Map.empty) options

module PaymentIntentsVerifyMicrodeposits =

    type VerifyMicrodepositsOptions = {
        [<Config.Path>]Intent: string
        ///<summary>Two positive integers, in *cents*, equal to the values of the microdeposits sent to the bank account.</summary>
        [<Config.Form>]Amounts: int list option
        ///<summary>A six-character code starting with SM present in the microdeposit sent to the bank account.</summary>
        [<Config.Form>]DescriptorCode: string option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
    }
    with
        static member New(intent: string, ?amounts: int list, ?descriptorCode: string, ?expand: string list) =
            {
                Intent = intent
                Amounts = amounts
                DescriptorCode = descriptorCode
                Expand = expand
            }

    ///<summary><p>Verifies microdeposits on a PaymentIntent object.</p></summary>
    let VerifyMicrodeposits settings (options: VerifyMicrodepositsOptions) =
        $"/v1/payment_intents/{options.Intent}/verify_microdeposits"
        |> RestApi.postAsync<_, PaymentIntent> settings (Map.empty) options

module PaymentMethodConfigurations =

    type ListOptions = {
        ///<summary>The Connect application to filter by.</summary>
        [<Config.Query>]Application: string option
        ///<summary>A cursor for use in pagination. `ending_before` is an object ID that defines your place in the list. For instance, if you make a list request and receive 100 objects, starting with `obj_bar`, your subsequent call can include `ending_before=obj_bar` in order to fetch the previous page of the list.</summary>
        [<Config.Query>]EndingBefore: string option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Query>]Expand: string list option
        ///<summary>A limit on the number of objects to be returned. Limit can range between 1 and 100, and the default is 10.</summary>
        [<Config.Query>]Limit: int option
        ///<summary>A cursor for use in pagination. `starting_after` is an object ID that defines your place in the list. For instance, if you make a list request and receive 100 objects, ending with `obj_foo`, your subsequent call can include `starting_after=obj_foo` in order to fetch the next page of the list.</summary>
        [<Config.Query>]StartingAfter: string option
    }
    with
        static member New(?application: string, ?endingBefore: string, ?expand: string list, ?limit: int, ?startingAfter: string) =
            {
                Application = application
                EndingBefore = endingBefore
                Expand = expand
                Limit = limit
                StartingAfter = startingAfter
            }

    ///<summary><p>List payment method configurations</p></summary>
    let List settings (options: ListOptions) =
        let qs = [("application", options.Application |> box); ("ending_before", options.EndingBefore |> box); ("expand", options.Expand |> box); ("limit", options.Limit |> box); ("starting_after", options.StartingAfter |> box)] |> Map.ofList
        $"/v1/payment_method_configurations"
        |> RestApi.getAsync<StripeList<PaymentMethodConfiguration>> settings qs

