module PaymentMethodDomains =

    type ListOptions = {
        ///<summary>The domain name that this payment method domain object represents.</summary>
        [<Config.Query>]DomainName: string option
        ///<summary>Whether this payment method domain is enabled. If the domain is not enabled, payment methods will not appear in Elements or Embedded Checkout</summary>
        [<Config.Query>]Enabled: bool option
        ///<summary>A cursor for use in pagination. `ending_before` is an object ID that defines your place in the list. For instance, if you make a list request and receive 100 objects, starting with `obj_bar`, your subsequent call can include `ending_before=obj_bar` in order to fetch the previous page of the list.</summary>
        [<Config.Query>]EndingBefore: string option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Query>]Expand: string list option
        ///<summary>A limit on the number of objects to be returned. Limit can range between 1 and 100, and the default is 10.</summary>
        [<Config.Query>]Limit: int option
        ///<summary>A cursor for use in pagination. `starting_after` is an object ID that defines your place in the list. For instance, if you make a list request and receive 100 objects, ending with `obj_foo`, your subsequent call can include `starting_after=obj_foo` in order to fetch the next page of the list.</summary>
        [<Config.Query>]StartingAfter: string option
    }
    with
        static member New(?domainName: string, ?enabled: bool, ?endingBefore: string, ?expand: string list, ?limit: int, ?startingAfter: string) =
            {
                DomainName = domainName
                Enabled = enabled
                EndingBefore = endingBefore
                Expand = expand
                Limit = limit
                StartingAfter = startingAfter
            }

    ///<summary><p>Lists the details of existing payment method domains.</p></summary>
    let List settings (options: ListOptions) =
        let qs = [("domain_name", options.DomainName |> box); ("enabled", options.Enabled |> box); ("ending_before", options.EndingBefore |> box); ("expand", options.Expand |> box); ("limit", options.Limit |> box); ("starting_after", options.StartingAfter |> box)] |> Map.ofList
        $"/v1/payment_method_domains"
        |> RestApi.getAsync<StripeList<PaymentMethodDomain>> settings qs

    type CreateOptions = {
        ///<summary>The domain name that this payment method domain object represents.</summary>
        [<Config.Form>]DomainName: string
        ///<summary>Whether this payment method domain is enabled. If the domain is not enabled, payment methods that require a payment method domain will not appear in Elements or Embedded Checkout.</summary>
        [<Config.Form>]Enabled: bool option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
    }
    with
        static member New(domainName: string, ?enabled: bool, ?expand: string list) =
            {
                DomainName = domainName
                Enabled = enabled
                Expand = expand
            }

    ///<summary><p>Creates a payment method domain.</p></summary>
    let Create settings (options: CreateOptions) =
        $"/v1/payment_method_domains"
        |> RestApi.postAsync<_, PaymentMethodDomain> settings (Map.empty) options

    type RetrieveOptions = {
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Query>]Expand: string list option
        [<Config.Path>]PaymentMethodDomain: string
    }
    with
        static member New(paymentMethodDomain: string, ?expand: string list) =
            {
                Expand = expand
                PaymentMethodDomain = paymentMethodDomain
            }

    ///<summary><p>Retrieves the details of an existing payment method domain.</p></summary>
    let Retrieve settings (options: RetrieveOptions) =
        let qs = [("expand", options.Expand |> box)] |> Map.ofList
        $"/v1/payment_method_domains/{options.PaymentMethodDomain}"
        |> RestApi.getAsync<PaymentMethodDomain> settings qs

    type UpdateOptions = {
        [<Config.Path>]PaymentMethodDomain: string
        ///<summary>Whether this payment method domain is enabled. If the domain is not enabled, payment methods that require a payment method domain will not appear in Elements or Embedded Checkout.</summary>
        [<Config.Form>]Enabled: bool option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
    }
    with
        static member New(paymentMethodDomain: string, ?enabled: bool, ?expand: string list) =
            {
                PaymentMethodDomain = paymentMethodDomain
                Enabled = enabled
                Expand = expand
            }

    ///<summary><p>Updates an existing payment method domain.</p></summary>
    let Update settings (options: UpdateOptions) =
        $"/v1/payment_method_domains/{options.PaymentMethodDomain}"
        |> RestApi.postAsync<_, PaymentMethodDomain> settings (Map.empty) options

module PaymentMethodDomainsValidate =

    type ValidateOptions = {
        [<Config.Path>]PaymentMethodDomain: string
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
    }
    with
        static member New(paymentMethodDomain: string, ?expand: string list) =
            {
                PaymentMethodDomain = paymentMethodDomain
                Expand = expand
            }

    ///<summary><p>Some payment methods might require additional steps to register a domain. If the requirements weren’t satisfied when the domain was created, the payment method will be inactive on the domain.
    ///The payment method doesn’t appear in Elements or Embedded Checkout for this domain until it is active.</p>
    ///<p>To activate a payment method on an existing payment method domain, complete the required registration steps specific to the payment method, and then validate the payment method domain with this endpoint.</p>
    ///<p>Related guides: <a href="/docs/payments/payment-methods/pmd-registration">Payment method domains</a>.</p></summary>
    let Validate settings (options: ValidateOptions) =
        $"/v1/payment_method_domains/{options.PaymentMethodDomain}/validate"
        |> RestApi.postAsync<_, PaymentMethodDomain> settings (Map.empty) options

