        [<Config.Form>]PaymentMethodConfiguration: string option
        ///<summary>When included, this hash creates a PaymentMethod that is set as the [`payment_method`](https://docs.stripe.com/api/setup_intents/object#setup_intent_object-payment_method)
        ///value in the SetupIntent.</summary>
        [<Config.Form>]PaymentMethodData: Create'PaymentMethodData option
        ///<summary>Payment method-specific configuration for this SetupIntent.</summary>
        [<Config.Form>]PaymentMethodOptions: Create'PaymentMethodOptions option
        ///<summary>The list of payment method types (for example, card) that this SetupIntent can use. If you don't provide this, Stripe will dynamically show relevant payment methods from your [payment method settings](https://dashboard.stripe.com/settings/payment_methods). A list of valid payment method types can be found [here](https://docs.stripe.com/api/payment_methods/object#payment_method_object-type).</summary>
        [<Config.Form>]PaymentMethodTypes: string list option
        ///<summary>The URL to redirect your customer back to after they authenticate or cancel their payment on the payment method's app or site. To redirect to a mobile application, you can alternatively supply an application URI scheme. This parameter can only be used with [`confirm=true`](https://docs.stripe.com/api/setup_intents/create#create_setup_intent-confirm).</summary>
        [<Config.Form>]ReturnUrl: string option
