    ///<summary><p>Creates a SetupIntent object.</p>
    ///<p>After you create the SetupIntent, attach a payment method and <a href="/docs/api/setup_intents/confirm">confirm</a>
    ///it to collect any required permissions to charge the payment method later.</p></summary>
    let Create settings (options: CreateOptions) =
        $"/v1/setup_intents"
        |> RestApi.postAsync<_, SetupIntent> settings (Map.empty) options

    type RetrieveOptions = {
        ///<summary>The client secret of the SetupIntent. We require this string if you use a publishable key to retrieve the SetupIntent.</summary>
        [<Config.Query>]ClientSecret: string option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Query>]Expand: string list option
        [<Config.Path>]Intent: string
    }
    with
        static member New(intent: string, ?expand: string list, ?clientSecret: string) =
            {
                ClientSecret = clientSecret
                Expand = expand
                Intent = intent
            }

    ///<summary><p>Retrieves the details of a SetupIntent that has previously been created. </p>
    ///<p>Client-side retrieval using a publishable key is allowed when the <code>client_secret</code> is provided in the query string. </p>
    ///<p>When retrieved with a publishable key, only a subset of properties will be returned. Please refer to the <a href="#setup_intent_object">SetupIntent</a> object reference for more details.</p></summary>
    let Retrieve settings (options: RetrieveOptions) =
        let qs = [("client_secret", options.ClientSecret |> box); ("expand", options.Expand |> box)] |> Map.ofList
        $"/v1/setup_intents/{options.Intent}"
        |> RestApi.getAsync<SetupIntent> settings qs

