    type ConfirmOptions = {
        [<Config.Path>]Intent: string
        ///<summary>ID of the ConfirmationToken used to confirm this SetupIntent.
        ///If the provided ConfirmationToken contains properties that are also being provided in this request, such as `payment_method`, then the values in this request will take precedence.</summary>
        [<Config.Form>]ConfirmationToken: string option
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
        [<Config.Form>]MandateData: Choice<Confirm'MandateDataSecretKey,string,Confirm'MandateDataClientKey> option
        ///<summary>ID of the payment method (a PaymentMethod, Card, or saved Source object) to attach to this SetupIntent.</summary>
        [<Config.Form>]PaymentMethod: string option
        ///<summary>When included, this hash creates a PaymentMethod that is set as the [`payment_method`](https://docs.stripe.com/api/setup_intents/object#setup_intent_object-payment_method)
        ///value in the SetupIntent.</summary>
        [<Config.Form>]PaymentMethodData: Confirm'PaymentMethodData option
        ///<summary>Payment method-specific configuration for this SetupIntent.</summary>
        [<Config.Form>]PaymentMethodOptions: Confirm'PaymentMethodOptions option
        ///<summary>The URL to redirect your customer back to after they authenticate on the payment method's app or site.
        ///If you'd prefer to redirect to a mobile application, you can alternatively supply an application URI scheme.
        ///This parameter is only used for cards and other redirect-based payment methods.</summary>
        [<Config.Form>]ReturnUrl: string option
        ///<summary>Set to `true` when confirming server-side and using Stripe.js, iOS, or Android client-side SDKs to handle the next actions.</summary>
        [<Config.Form>]UseStripeSdk: bool option
    }
    with
        static member New(intent: string, ?confirmationToken: string, ?expand: string list, ?mandateData: Choice<Confirm'MandateDataSecretKey,string,Confirm'MandateDataClientKey>, ?paymentMethod: string, ?paymentMethodData: Confirm'PaymentMethodData, ?paymentMethodOptions: Confirm'PaymentMethodOptions, ?returnUrl: string, ?useStripeSdk: bool) =
            {
                Intent = intent
                ConfirmationToken = confirmationToken
                Expand = expand
                MandateData = mandateData
                PaymentMethod = paymentMethod
                PaymentMethodData = paymentMethodData
                PaymentMethodOptions = paymentMethodOptions
                ReturnUrl = returnUrl
                UseStripeSdk = useStripeSdk
            }

    ///<summary><p>Confirm that your customer intends to set up the current or
    ///provided payment method. For example, you would confirm a SetupIntent
    ///when a customer hits the “Save” button on a payment method management
    ///page on your website.</p>
    ///<p>If the selected payment method does not require any additional
    ///steps from the customer, the SetupIntent will transition to the
    ///<code>succeeded</code> status.</p>
    ///<p>Otherwise, it will transition to the <code>requires_action</code> status and
    ///suggest additional actions via <code>next_action</code>. If setup fails,
    ///the SetupIntent will transition to the
    ///<code>requires_payment_method</code> status or the <code>canceled</code> status if the
    ///confirmation limit is reached.</p></summary>
    let Confirm settings (options: ConfirmOptions) =
        $"/v1/setup_intents/{options.Intent}/confirm"
        |> RestApi.postAsync<_, SetupIntent> settings (Map.empty) options

