    type CreateOptions = {
        ///<summary>Events sent to this endpoint will be generated with this Stripe Version instead of your account's default Stripe Version.</summary>
        [<Config.Form>]ApiVersion: Create'ApiVersion option
        ///<summary>Whether this endpoint should receive events from connected accounts (`true`), or from your account (`false`). Defaults to `false`.</summary>
        [<Config.Form>]Connect: bool option
        ///<summary>An optional description of what the webhook is used for.</summary>
        [<Config.Form>]Description: Choice<string,string> option
        ///<summary>The list of events to enable for this endpoint. You may specify `['*']` to enable all events, except those that require explicit selection.</summary>
        [<Config.Form>]EnabledEvents: Create'EnabledEvents list
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Form>]Expand: string list option
        ///<summary>Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`.</summary>
        [<Config.Form>]Metadata: Map<string, string> option
        ///<summary>The URL of the webhook endpoint.</summary>
        [<Config.Form>]Url: string
    }
    with
        static member New(enabledEvents: Create'EnabledEvents list, url: string, ?apiVersion: Create'ApiVersion, ?connect: bool, ?description: Choice<string,string>, ?expand: string list, ?metadata: Map<string, string>) =
            {
                ApiVersion = apiVersion
                Connect = connect
                Description = description
                EnabledEvents = enabledEvents
                Expand = expand
                Metadata = metadata
                Url = url
            }

    ///<summary><p>A webhook endpoint must have a <code>url</code> and a list of <code>enabled_events</code>. You may optionally specify the Boolean <code>connect</code> parameter. If set to true, then a Connect webhook endpoint that notifies the specified <code>url</code> about events from all connected accounts is created; otherwise an account webhook endpoint that notifies the specified <code>url</code> only about events from your account is created. You can also create webhook endpoints in the <a href="https://dashboard.stripe.com/account/webhooks">webhooks settings</a> section of the Dashboard.</p></summary>
    let Create settings (options: CreateOptions) =
        $"/v1/webhook_endpoints"
        |> RestApi.postAsync<_, WebhookEndpoint> settings (Map.empty) options

    type DeleteOptions = {
        [<Config.Path>]WebhookEndpoint: string
    }
    with
        static member New(webhookEndpoint: string) =
            {
                WebhookEndpoint = webhookEndpoint
            }

    ///<summary><p>You can also delete webhook endpoints via the <a href="https://dashboard.stripe.com/account/webhooks">webhook endpoint management</a> page of the Stripe dashboard.</p></summary>
    let Delete settings (options: DeleteOptions) =
        $"/v1/webhook_endpoints/{options.WebhookEndpoint}"
        |> RestApi.deleteAsync<DeletedWebhookEndpoint> settings (Map.empty)

    type RetrieveOptions = {
        ///<summary>Specifies which fields in the response should be expanded.</summary>
        [<Config.Query>]Expand: string list option
        [<Config.Path>]WebhookEndpoint: string
    }
    with
        static member New(webhookEndpoint: string, ?expand: string list) =
            {
                Expand = expand
                WebhookEndpoint = webhookEndpoint
            }

    ///<summary><p>Retrieves the webhook endpoint with the given ID.</p></summary>
    let Retrieve settings (options: RetrieveOptions) =
        let qs = [("expand", options.Expand |> box)] |> Map.ofList
        $"/v1/webhook_endpoints/{options.WebhookEndpoint}"
        |> RestApi.getAsync<WebhookEndpoint> settings qs

